using System;
using System.Diagnostics;
using SkiaSharp;

const int iterations = 500;
const int width = 3840;
const int height = 2160;

long initialMemory = GC.GetTotalMemory(true);
long peakMemory = initialMemory;

Console.WriteLine($"Initial memory: {initialMemory / 1024.0:F0} KB");
Console.WriteLine($"Drawing {iterations} frames at {width}x{height}...");

var sw = Stopwatch.StartNew();

for (int i = 0; i < iterations; i++)
{
    using var bitmap = new SKBitmap(width, height);
    using var canvas = new SKCanvas(bitmap);
    canvas.Clear(SKColors.White);

    using var paint = new SKPaint { Style = SKPaintStyle.Fill, IsAntialias = true };

    for (int x = 0; x < width; x += 20)
        for (int y = 0; y < height; y += 20)
        {
            paint.Color = new SKColor((byte)(x % 256), (byte)(y % 256), (byte)((x + y) % 256));
            canvas.DrawRect(x, y, 18, 18, paint);
        }

    using var path = new SKPath();
    for (int j = 0; j < 50; j++)
    {
        path.Reset();
        path.MoveTo(j * 10, 0);
        path.LineTo(width, j * 10);
        path.LineTo(width - j * 10, height);
        path.LineTo(0, height - j * 10);
        path.Close();
        paint.Style = SKPaintStyle.Stroke;
        paint.StrokeWidth = 2;
        paint.Color = SKColors.Blue;
        canvas.DrawPath(path, paint);
    }

    using var shader = SKShader.CreateColor(SKColors.Red);
    paint.Shader = shader;
    paint.Style = SKPaintStyle.Fill;
    canvas.DrawRect(0, 0, 100, 100, paint);
    paint.Shader = null;

    using var image = SKImage.FromBitmap(bitmap);
    using var data = image.Encode(SKEncodedImageFormat.Png, 80);

    if (i % 100 == 0)
    {
        long currentMemory = GC.GetTotalMemory(false);
        if (currentMemory > peakMemory) peakMemory = currentMemory;
        Console.WriteLine($"  Iteration {i}: memory = {currentMemory / 1024.0:F0} KB");
    }
}

sw.Stop();
GC.Collect();
GC.WaitForPendingFinalizers();
GC.Collect();

long finalMemory = GC.GetTotalMemory(true);
Console.WriteLine($"Results: Initial={initialMemory/1024}KB Final={finalMemory/1024}KB Peak={peakMemory/1024}KB Growth={(finalMemory-initialMemory)/1024}KB");
Console.WriteLine("SUCCESS: test completed");
